import React, { useEffect, useState } from "react";
import "./Placement.css";

export default function Placement() {
  const [placements, setPlacements] = useState([]);
  const user = JSON.parse(localStorage.getItem("loggedInUser"));

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("placements")) || [];
    setPlacements(data);
  }, []);

  const handleApply = (id) => {
    alert(`Applied to placement ID: ${id}`);
  };

  const handleDelete = (id) => {
    const updated = placements.filter((item) => item.id !== id);
    setPlacements(updated);
    localStorage.setItem("placements", JSON.stringify(updated));
  };

  const handleEdit = (id) => {
    alert(`Edit functionality for ID: ${id}`);
  };

  return (
    <div className="placement-container">
      <h2>Placement Opportunities</h2>
      {placements.length === 0 ? (
        <p>No placements available.</p>
      ) : (
        <div className="placement-list">
          {placements.map((item) => (
            <div key={item.id} className="placement-card">
              <h3>{item.title}</h3>
              <p>{item.description}</p>
              <p><strong>Company:</strong> {item.company}</p>
              <p><strong>Package:</strong> {item.package}</p>

              <div className="actions">
                {(user.role === "Admin" || user.role === "HR") && (
                  <>
                    <button onClick={() => handleEdit(item.id)}>Edit</button>
                    {user.role === "Admin" && (
                      <button onClick={() => handleDelete(item.id)}>Delete</button>
                    )}
                  </>
                )}

                {user.role === "Student" && (
                  <button onClick={() => handleApply(item.id)}>Apply</button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
